// ── Real elevation profile based on Komoot data ──
// Route highlights: flat 0-30km, Heuvelrug bump 30-60, valley 60-90,
// Veluwe climbs 90-180, descent home 180-243
const ELEV = [
  5,5,6,8,10,12,15,18,22,26,28,30,35,38,40,38,34,28,22,16,12,10,8,6,5,5,6,8,10,12,
  14,18,24,32,42,52,58,62,58,50,42,34,26,20,15,10,8,6,5,5,5,6,8,10,12,14,16,18,20,22,
  20,18,15,12,10,8,10,14,20,28,38,50,62,72,78,80,78,72,64,55,48,42,38,42,48,56,64,72,78,80,
  78,72,65,58,52,48,44,48,54,60,66,72,76,78,76,70,62,55,48,42,38,35,38,44,50,56,60,62,60,55,
  48,40,32,25,20,16,12,18,24,30,36,40,38,32,26,20,15,12,10,8,8,10,12,15,18,20,18,15,12,10,
  8,6,5,5,6,8,10,12,14,16,14,12,10,8,6,5,5,6,8,10,12,14,12,10,8,6,5,5,5,5,
  5,5,5,
];

function ElevSVG() {
  const W=340, H=85;
  const max = Math.max(...ELEV);
  const pts = ELEV.map((e,i)=>({x:i*(W/(ELEV.length-1)),y:H-(e/max)*H*0.88}));
  const line = pts.map((p,i)=>`${i===0?"M":"L"} ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(" ");
  const fill = line + ` L ${W} ${H} L 0 ${H} Z`;
  const marks = [{km:60,c:GREEN},{km:125,c:ORANGE},{km:170,c:RED},{km:207,c:DIM}];
  return (
    <svg viewBox={`0 0 ${W} ${H+14}`} style={{width:"100%"}}>
      <defs>
        <linearGradient id="eg" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor={GREEN}/>
          <stop offset="35%" stopColor={ORANGE}/>
          <stop offset="70%" stopColor={RED}/>
          <stop offset="100%" stopColor="#C03010"/>
        </linearGradient>
        <linearGradient id="ef" x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" stopColor={ORANGE} stopOpacity="0.22"/>
          <stop offset="100%" stopColor={ORANGE} stopOpacity="0.02"/>
        </linearGradient>
      </defs>
      {[60,122,182].map(km=>(
        <line key={km} x1={(km/243)*W} y1={0} x2={(km/243)*W} y2={H} stroke="#252525" strokeWidth="1" strokeDasharray="2 3"/>
      ))}
      <path d={fill} fill="url(#ef)"/>
      <path d={line} fill="none" stroke="url(#eg)" strokeWidth="1.8"/>
      {marks.map(({km,c})=>{
        const xi=Math.round((km/243)*(ELEV.length-1));
        const y=H-(ELEV[xi]/max)*H*0.88;
        return <circle key={km} cx={(km/243)*W} cy={y} r={3.5} fill={c} stroke="#0D0D0D" strokeWidth="1.5"/>;
      })}
      {[{km:0,l:"0km"},{km:60,l:"60"},{km:122,l:"122"},{km:182,l:"182"},{km:243,l:"243km"}].map(({km,l})=>(
        <text key={l} x={(km/243)*W} y={H+12} textAnchor="middle" fill="#555" fontSize="6" fontFamily="monospace">{l}</text>
      ))}
    </svg>
  );
}

// ── Route visualization matching real Komoot route shape ──
// Real route: Bussum/Hilversum (top-left) → south through Bilthoven/Zeist/Driebergen
// → east through Veenendaal → bigger loop east via Ede → Veluwe (Radio Kootwijk, Apeldoorn)
// → north via Vaassen/Kroondomein → west via Putten/Voorthuizen/Nijkerk/Amersfoort → home
function RouteVis() {
  const W=340, H=200;
  const pts = [
    // Start Bussum (top-left)
    {km:0,   x:0.12, y:0.18, label:"START", k:GREEN, big:true},
    {km:5,   x:0.13, y:0.25},
    // Down via Hilversum/Bilthoven
    {km:15,  x:0.14, y:0.40},
    {km:25,  x:0.13, y:0.55},
    // Through Utrecht/Zeist area
    {km:35,  x:0.16, y:0.70},
    {km:45,  x:0.19, y:0.78},
    // Towards Amerongen (south-east)
    {km:55,  x:0.24, y:0.82},
    {km:60,  x:0.28, y:0.82, label:"JUMBO", k:GREEN, stop:true},
    // East through Veenendaal/Ede area
    {km:70,  x:0.34, y:0.78},
    {km:80,  x:0.42, y:0.74},
    {km:88,  x:0.48, y:0.70, label:"GEL", k:ORANGE},
    {km:95,  x:0.55, y:0.66},
    // Up through Ede towards Apeldoorn/Veluwe
    {km:105, x:0.62, y:0.58},
    {km:115, x:0.70, y:0.48},
    {km:125, x:0.76, y:0.40, label:"SPAR", k:ORANGE, stop:true},
    // Deep into Veluwe — northeast curve
    {km:135, x:0.84, y:0.32},
    {km:145, x:0.86, y:0.20},
    {km:152, x:0.84, y:0.14, label:"GEL", k:RED},
    // Top of route — Vaassen/Kroondomein
    {km:160, x:0.78, y:0.12},
    {km:165, x:0.72, y:0.16},
    {km:170, x:0.66, y:0.22, label:"PLUS", k:RED, stop:true},
    // Back west via Putten/Voorthuizen
    {km:180, x:0.58, y:0.24},
    {km:190, x:0.49, y:0.28},
    {km:198, x:0.42, y:0.30, label:"GEL", k:"#C03010"},
    // Nijkerk area
    {km:207, x:0.34, y:0.30, label:"SHELL?", k:DIM, opt:true},
    // Back through Bussum
    {km:220, x:0.26, y:0.28},
    {km:232, x:0.18, y:0.22},
    {km:243, x:0.12, y:0.18, label:"FINISH", k:GOLD, big:true},
  ];
  const x = p => p.x * W;
  const y = p => p.y * H;
  let d = `M ${x(pts[0]).toFixed(1)} ${y(pts[0]).toFixed(1)}`;
  for(let i=1;i<pts.length;i++){
    const a=pts[i-1], b=pts[i];
    const mx=(x(a)+x(b))/2, my=(y(a)+y(b))/2;
    d += ` Q ${x(a).toFixed(1)} ${y(a).toFixed(1)} ${mx.toFixed(1)} ${my.toFixed(1)}`;
  }
  d += ` T ${x(pts[pts.length-1]).toFixed(1)} ${y(pts[pts.length-1]).toFixed(1)}`;

  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{width:"100%"}}>
      <defs>
        <linearGradient id="rg" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor={GREEN}/><stop offset="40%" stopColor={ORANGE}/>
          <stop offset="70%" stopColor={RED}/><stop offset="100%" stopColor="#C03010"/>
        </linearGradient>
      </defs>
      {/* City labels - subtle */}
      {[
        {n:"Bussum",  x:0.10,y:0.10},
        {n:"Utrecht", x:0.08,y:0.68},
        {n:"Amersfoort",x:0.32,y:0.50},
        {n:"Ede",     x:0.50,y:0.78},
        {n:"Veluwe",  x:0.78,y:0.06},
        {n:"Apeldoorn",x:0.88,y:0.40},
        {n:"Nijkerk", x:0.32,y:0.22},
      ].map((c,i)=>(
        <text key={i} x={c.x*W} y={c.y*H} fill="#2C2C2C" fontSize="5.5" fontFamily="monospace" textAnchor="middle">{c.n}</text>
      ))}
      {/* Route line - shadow */}
      <path d={d} fill="none" stroke="#0A0A0A" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round"/>
      {/* Route line - gradient */}
      <path d={d} fill="none" stroke="url(#rg)" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
      {/* Stop markers */}
      {pts.filter(p=>p.label).map((p,i)=>{
        const px=x(p), py=y(p);
        const labelBelow = py < H*0.3;
        return (
          <g key={i}>
            {(p.stop||p.big) && <circle cx={px} cy={py} r={p.big?7:9} fill={p.k+"20"} stroke={p.k} strokeWidth="1.5"/>}
            <circle cx={px} cy={py} r={p.big?4:p.stop?3.5:2.5} fill={p.k} stroke="#0D0D0D" strokeWidth="1.5"/>
            <text x={px} y={labelBelow?py+15:py-10} textAnchor="middle" fill={p.opt?"#666":p.k}
              fontSize={p.big?"8":"7"} fontWeight="700" fontFamily="monospace">{p.label}</text>
          </g>
        );
      })}
    </svg>
  );
}

const S = (style={}) => ({fontFamily:"'Courier New',monospace",...style});

function Lbl({c,mt=0,children}) {
  return <div style={S({fontSize:"10px",letterSpacing:"3px",color:c||GOLD,marginBottom:"12px",marginTop:mt,textTransform:"uppercase"})}>/{children}/</div>;
}
function Card({children,bl,style={}}) {
  return <div style={S({background:"#181818",border:"1px solid #282828",borderLeft:bl?`3px solid ${bl}`:undefined,padding:"14px",marginBottom:"8px",...style})}>{children}</div>;
}

